import assert from 'node:assert/strict';
import { formatCustomerName } from './src/customer.js';
import { formatOperatorName } from './src/operator.js';

const user = { firstName: ' Ada ', lastName: ' Lovelace ' };
assert.equal(formatCustomerName(user), 'Lovelace, Ada');
assert.equal(formatOperatorName(user), 'Lovelace, Ada');
console.log('ok');
